const long long N &#x3D; 9e3;&#x2F;&#x2F;通过知道前面的n^1&#x2F;3的质数可以推断后面n^2&#x2F;3的质数所以可以适当减小
bool np[N];
int prime[N], pi[N];
int getprime() &#123;
    int cnt &#x3D; 0;
    np[0] &#x3D; np[1] &#x3D; true;
    pi[0] &#x3D; pi[1] &#x3D; 0;
    for(int i &#x3D; 2; i &lt; N; ++i) &#123;
        if(!np[i]) prime[++cnt] &#x3D; i;
        pi[i] &#x3D; cnt;
        for(int j &#x3D; 1; j &lt;&#x3D; cnt &amp;&amp; i * prime[j] &lt; N; ++j) &#123;
            np[i * prime[j]] &#x3D; true;
            if(i % prime[j] &#x3D;&#x3D; 0)   break;
