        &#x2F;&#x2F; Checking for cycle
        if (marked[x] &#x3D;&#x3D; true) &#123;
            continue;
        &#125;
        minimum_cost +&#x3D; p.first;
        marked[x] &#x3D; true;
        for (const PII &amp;neighbor : graph[x]) &#123;
            int y &#x3D; neighbor.second;
            if (marked[y] &#x3D;&#x3D; false) &#123;
                Q.push(neighbor);
            &#125;
        &#125;
    &#125;
    return minimum_cost;
&#125;

